import zlib, base64

GRAPHS = {
    # [@document<plan_graph]{(@compressed<>)}
    "plan_graph": "",

    # [@document<spec_graph]{(@compressed<>)}
    "spec_graph": "",

    # [@document<flow_graph]{(@compressed<>)}
    "flow_graph": "",

    # [@document<dep_graph]{(@compressed<>)}
    "dep_graph": "",

    # [@document<gap_graph]{(@compressed<>)}
    "gap_graph": "",

}

def get_graph(name):
    raw = GRAPHS.get(name)
    if not raw:
        return None
    return zlib.decompress(base64.b64decode(raw)).decode("utf-8")

def list_graphs():
    return list(GRAPHS.keys())
